import { NextResponse } from "next/server";
import { getFounder } from "@/lib/auth";
import { db } from "@/lib/db";
import { generateApiKeyPlaintext } from "@/lib/apiKeyAuth";

/**
 * GET  /api/auth/api-keys         → list non-revoked keys for the current founder
 *   Response: [{ id, label, prefix, createdAt, lastUsedAt }]
 *
 * POST /api/auth/api-keys         → mint a new key
 *   Body: { label: string }       (human label shown in the UI — e.g. "Dialectic on laptop")
 *   Response: { id, plaintext, prefix, label, createdAt }
 *   The `plaintext` field is returned ONCE and never again. Copy it immediately.
 *
 * DELETE /api/auth/api-keys?id=   → revoke (soft-delete) a key
 *
 * All three handlers require a cookie session (intentionally — you shouldn't
 * use an API key to mint more API keys).
 */
export async function GET() {
  const founder = await getFounder();
  if (!founder) {
    return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
  }
  const keys = await db.apiKey.findMany({
    where: { founderId: founder.id, revokedAt: null },
    select: {
      id: true,
      label: true,
      prefix: true,
      createdAt: true,
      lastUsedAt: true,
      scopes: true,
    },
    orderBy: { createdAt: "desc" },
  });
  return NextResponse.json(keys);
}

export async function POST(req: Request) {
  const founder = await getFounder();
  if (!founder) {
    return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
  }
  let body: { label?: string; scopes?: string };
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
  }
  const label = (body.label || "").trim();
  if (!label) {
    return NextResponse.json(
      { error: "`label` is required (e.g. \"Dialectic on laptop\")" },
      { status: 400 },
    );
  }

  const { plaintext, prefix, keyHash } = await generateApiKeyPlaintext();
  const key = await db.apiKey.create({
    data: {
      organizationId: founder.organizationId,
      founderId: founder.id,
      label,
      prefix,
      keyHash,
      scopes: body.scopes || "",
    },
    select: { id: true, label: true, prefix: true, createdAt: true },
  });

  await db.auditEvent.create({
    data: {
      organizationId: founder.organizationId,
      founderId: founder.id,
      action: "api_key.create",
      detail: `Minted API key '${label}' (${prefix}…)`,
    },
  });

  return NextResponse.json({ ...key, plaintext });
}

export async function DELETE(req: Request) {
  const founder = await getFounder();
  if (!founder) {
    return NextResponse.json({ error: "Not authenticated" }, { status: 401 });
  }
  const url = new URL(req.url);
  const id = url.searchParams.get("id");
  if (!id) {
    return NextResponse.json({ error: "`id` query param is required" }, { status: 400 });
  }
  const key = await db.apiKey.findFirst({
    where: { id, founderId: founder.id, revokedAt: null },
  });
  if (!key) {
    return NextResponse.json({ error: "Key not found" }, { status: 404 });
  }
  await db.apiKey.update({
    where: { id: key.id },
    data: { revokedAt: new Date() },
  });
  await db.auditEvent.create({
    data: {
      organizationId: founder.organizationId,
      founderId: founder.id,
      action: "api_key.revoke",
      detail: `Revoked API key '${key.label}' (${key.prefix}…)`,
    },
  });
  return NextResponse.json({ ok: true });
}

model Founder {
  id             String       @id @default(cuid())
  organizationId String
  organization   Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  name                    String
  username                String
  email                   String
  passwordHash            String
  // Role ladder — see src/lib/roles.ts for the predicate helpers and
  // the full description of each tier:
  //   admin   → full read + write + can change other founders' roles
  //   founder → full read + write
  //   viewer  → read-only; every write API returns 403 and every UI
  //              affordance for writes is hidden
  // Default "founder" preserves prior behaviour: anyone added via
  // scripts/add-founder.ts is read+write unless explicitly seeded
  // with ADD_FOUNDER_ROLE=viewer or =admin. Validation lives at the
  // application layer; the column stays TEXT so adding a future tier
  // is a docstring + helper change, not a migration.
  role                    String    @default("founder") // admin | founder | viewer
  bio                     String?
  displayName             String?
  roleTitle               String?
  publicUrl               String?
  avatar                  String?
  accountNudgeDismissedAt DateTime?

  /// Maps to FounderProfile.id in Noosphere
  noosphereId String?

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  sessions                   Session[]
  uploads                    Upload[]
  auditEvents                AuditEvent[]
  deletionRequests           DeletionRequest[]
  attributedConclusions      Conclusion[]                @relation("ConclusionFounder")
  researchSuggestions        ResearchSuggestion[]
  reviewResolutions          ReviewItem[]                @relation("ReviewResolver")
  publicationReviews         PublicationReview[]         @relation("PublicationReviewer")
  recalibrationOverrides     RecalibrationOverride[]
  apiKeys                    ApiKey[]
  conclusionDeletionRequests ConclusionDeletionRequest[]
  dashboardDismissals        DashboardDismissal[]
  resolvedContradictions     Contradiction[]             @relation("ContradictionResolver")
  revisionEvents             RevisionEvent[]
  publicReplies              PublicReply[]               @relation("PublicReplyFounder")
  attentionActions           AttentionAction[]
  decidedCritiques           CritiqueSubmission[]        @relation("CritiqueDecidedBy")
  confirmedBountyPayouts     CritiqueBountyPayout[]      @relation("CritiqueBountyConfirmedBy")

  /// Opt-in flag for the daily morning digest email summarising open
  /// high-severity attention items. Default `false` — silent until the
  /// founder explicitly opts in. See `src/lib/dailyDigestEmail.ts`.
  dailyDigestOptIn Boolean @default(false)

  @@unique([organizationId, email])
  @@unique([organizationId, username])
  @@index([organizationId])
}

/// Browser session (server-side row; cookie carries signed opaque token)
model Session {
  id             String   @id @default(cuid())
  organizationId String
  founderId      String
  token          String   @unique
  expiresAt      DateTime

model AuditEvent {
  id             String   @id @default(cuid())
  organizationId String
  founderId      String
  uploadId       String?
  action         String
  detail         String?
  createdAt      DateTime @default(now())

  founder      Founder      @relation(fields: [founderId], references: [id])
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  upload       Upload?      @relation(fields: [uploadId], references: [id], onDelete: SetNull)

  @@index([organizationId])
}

// ── Belief revision audit ledger ─────────────────────────────────────────
//
// Every committed revision (founder marks new evidence on a claim and
// confirms the propagation preview) appends one row here. The
// `preConfidenceSnapshot` is what makes time-replay work: replaying the
// ledger up to but not including a given event reconstructs the prior
// belief state exactly. `revertedAt` is the soft-delete: the public
// "/revisions/<id>" page renders an event regardless, but conclusion
// readers fall through to the previous non-reverted event.
model RevisionEvent {
  id             String @id @default(cuid())
  organizationId String
  /// Plan id from the noosphere engine (sha256 over inputs+thresholds);
  /// duplicates indicate idempotent re-submits and are allowed.
  planId         String
  /// Founder who confirmed the revision in the preview modal.
  founderId      String

  /// JSON: [{ claim_id, weight, new_evidence }] — the RevisionInput batch.
  inputsJson            String
  /// JSON: full RevisionPlan.to_dict() — frozen at commit time.
  planJson              String
  /// JSON: { conclusion_id: confidence_before } — the before-snapshot.
  preConfidenceSnapshot String
  /// Conclusions whose confidence changed by > δ at commit time. Stored
  /// as a denormalised JSON array of conclusion ids so the UI can build
  /// the "updated" pill query without parsing planJson on every page
  /// render. Source of truth is still planJson.
  affectedConclusionIds String @default("[]")

  /// `true` when the founder typed the K-cap confirmation phrase. Always
  /// `false` for revisions whose affected_count <= K; informational only.
  typedConfirmation Boolean @default(false)

  createdAt  DateTime  @default(now())
  revertedAt DateTime?

  founder      Founder      @relation(fields: [founderId], references: [id])
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([organizationId, createdAt])
  @@index([planId])
}

// ── API keys for machine-to-machine auth (Dialectic auto-sync, scripts, etc.) ─
//
// Store the *hash* of the key, never the plaintext. The plaintext is returned
// once at creation time. Revocation = set `revokedAt`. The key plaintext
// should look like `tcx_<founderId>_<64-hex-random>` so the client can send
// the founderId bits without a DB lookup for routing, and the random tail is
// the secret. `authenticateApiKey()` in src/lib/apiKeyAuth.ts implements
// the verification (bcrypt compare against `keyHash`).
model ApiKey {
  id             String @id @default(cuid())
  organizationId String
  /// Founder the key acts on behalf of — uploads are attributed to them.
  founderId      String

  /// Human label shown in the management UI (e.g. "Dialectic on laptop").
  label   String
  /// Short prefix of the plaintext (first 12 chars) — shown in UI for identification.
  prefix  String
  /// bcrypt hash of the full plaintext key. Never store plaintext.
  keyHash String
  /// Comma-separated scopes (e.g. "upload:write"). Empty = full founder scope.
  scopes  String @default("")

  createdAt  DateTime  @default(now())
  lastUsedAt DateTime?
  revokedAt  DateTime?

  founder      Founder      @relation(fields: [founderId], references: [id], onDelete: Cascade)
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([founderId])
  @@index([prefix])
}

// ── Method ↔ Conclusion linkage ───────────────────────────────────────────
//
// Bridge table: which registered methods produced this conclusion, and at
// what relative weight. A single conclusion may compose several methods
// (e.g. "empirical_calibration" + "adversarial_revision"), so the weights
// are not constrained to sum to 1 — they're independent contributions in
// [0, 1]. The `domain` column lets the track-record aggregator group by
// the conclusion's topical domain so we don't smooth across forecasting,
// policy design, etc.
//
// Idempotent: the linker upserts on (conclusionId, methodName, methodVersion)
// rather than appending.
model ConclusionMethod {
  id             String @id @default(cuid())

