  if (!b || now > b.resetAt) {
    b = { count: 0, resetAt: now + SUBSCRIBE_IP_WINDOW_MS };
    subscribeIpBuckets.set(ip, b);
  }
  if (b.count >= SUBSCRIBE_IP_MAX) {
    return { ok: false, retryAfterSec: Math.max(1, Math.ceil((b.resetAt - now) / 1000)) };
  }
  b.count += 1;
  return { ok: true };
}

